package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrintAndEscape() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withRecordSeparator("\r\n");
        CSVFormat spyCsvFormat = spy(csvFormat);
        CharSequence value = "abc,def";
        int offset = 0;
        int len = value.length();
        StringWriter out = new StringWriter();

        // When
        try {
            spyCsvFormat.getClass().getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class)
                    .setAccessible(true).invoke(spyCsvFormat, value, offset, len, out);
        } catch (Exception e) {
            e.printStackTrace();
        }

        // Then
        assertEquals("abc\",\"def", out.toString());
    }
}
